<svg viewBox="0 0 700 510" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-family="sans-serif" font-size="16" font-weight="700">ETF Flows Haven't Held a Direction for More Than Two Days All July</text>
  <text x="20" y="52" fill="#a1a1aa" font-family="sans-serif" font-size="13">Daily net spot Bitcoin ETF flow (July 6-15, US$ millions)</text>
  <line x1="40" y1="230" x2="680" y2="230" stroke="#3f3f46" stroke-width="1"/>
  <text x="30" y="234" text-anchor="end" font-family="sans-serif" font-size="13" fill="#71717a">0</text>
